import { ILeaveRepository } from '../leave/leave.repository';
import { IBalanceRepository } from '../balance/balance.repository';
import { INotificationRepository } from '../notification/notification.repository';
import { IAuditRepository } from '../audit/audit.repository';
import { LeaveRequest, LeaveRequestStatus } from '../leave/leave.model';
import { LeaveBalance } from '../balance/balance.model';
import { Notification } from '../notification/notification.model';
import { AuditLog } from '../audit/audit.model';
import { CreateLeaveRequestDto } from '../leave/leave.dto';
import { Pool } from '../../shared/db/connection';
import { NotFoundError, ConflictError, ForbiddenError } from '../../shared/errors';

export interface ILeaveManagementService {
  applyForLeave(dto: CreateLeaveRequestDto): Promise<LeaveRequest>;
  approveLeave(leaveId: string, approverId: string, comment?: string): Promise<LeaveRequest>;
  rejectLeave(leaveId: string, approverId: string, comment: string): Promise<LeaveRequest>;
  cancelLeave(leaveId: string, employeeId: string): Promise<LeaveRequest>;
  discardDraft(leaveId: string, employeeId: string): Promise<void>;
}

export class LeaveManagementService implements ILeaveManagementService {
  constructor(
    private readonly leaveRepo: ILeaveRepository,
    private readonly balanceRepo: IBalanceRepository,
    private readonly notificationRepo: INotificationRepository,
    private readonly auditRepo: IAuditRepository,
    private readonly db: Pool
  ) {}

  // ... existing methods applyForLeave, approveLeave, rejectLeave ...

  async cancelLeave(leaveId: string, employeeId: string): Promise<LeaveRequest> {
    const client = await this.db.connect();
    try {
      await client.query('BEGIN');
      const request = await this.leaveRepo.findById(leaveId, client);
      if (!request) {
        throw new NotFoundError('Leave request not found');
      }
      if (request.employee_id !== employeeId) {
        throw new ForbiddenError('You can only cancel your own leave requests');
      }
      if (request.status !== 'submitted' && request.status !== 'approved') {
        throw new ConflictError('Only submitted or approved requests can be cancelled');
      }

      const oldStatus = request.status;
      const days = this.calculateDays(request.start_date, request.end_date);
      const balance = await this.balanceRepo.findByEmployeeAndTypeAndYear(
        request.employee_id,
        request.leave_type_id,
        new Date(request.start_date).getFullYear(),
        client
      );
      if (!balance) {
        throw new NotFoundError('Leave balance not found');
      }

      if (oldStatus === 'submitted') {
        balance.pending_days = Number(balance.pending_days) - days;
      } else if (oldStatus === 'approved') {
        balance.used_days = Number(balance.used_days) - days;
      }
      await this.balanceRepo.update(balance, client);

      request.status = 'cancelled';
      request.updated_at = new Date();
      await this.leaveRepo.update(request, client);

      await this.auditRepo.create({
        entity_type: 'leave_request',
        entity_id: request.id,
        action: 'cancelled',
        changed_by: employeeId,
        old_values: { status: oldStatus },
        new_values: { status: 'cancelled' },
      }, client);

      await this.notificationRepo.create({
        recipient_id: request.approver_id || request.employee_id,
        leave_request_id: request.id,
        type: 'leave_cancelled',
        message: `Leave request ${request.id} has been cancelled by employee.`,
      }, client);

      await client.query('COMMIT');
      return request;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async discardDraft(leaveId: string, employeeId: string): Promise<void> {
    const client = await this.db.connect();
    try {
      await client.query('BEGIN');
      const request = await this.leaveRepo.findById(leaveId, client);
      if (!request) {
        throw new NotFoundError('Leave request not found');
      }
      if (request.employee_id !== employeeId) {
        throw new ForbiddenError('You can only discard your own drafts');
      }
      if (request.status !== 'draft') {
        throw new ConflictError('Only draft requests can be discarded');
      }

      request.status = 'cancelled';
      request.updated_at = new Date();
      await this.leaveRepo.update(request, client);

      await this.auditRepo.create({
        entity_type: 'leave_request',
        entity_id: request.id,
        action: 'discarded',
        changed_by: employeeId,
        old_values: { status: 'draft' },
        new_values: { status: 'cancelled' },
      }, client);

      await client.query('COMMIT');
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  private calculateDays(startDate: Date, endDate: Date): number {
    const diffTime = Math.abs(endDate.getTime() - startDate.getTime());
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; // inclusive
  }
